const { ContentType } = require('magicbell-js/dist/commonjs/user-client/http/types.js');
const { Environment } = require('magicbell-js/dist/commonjs/user-client/http/environment.js');

async function main() {
  try {
    const email = `${process.env.MAGICBELL_EMAIL}+${process.env.ZEALT_RUN_ID}@gmail.com`;

    // Generate JWT
    const token = jwt.sign(
      { user_email: email, api_key: process.env.MAGICBELL_API_KEY },
      process.env.MAGICBELL_SECRET_KEY,
      { algorithm: 'HS256' }
    );

    // Initialize client
    const client = new Client({ token });

    // Try to mark as seen
    if (client.notifications.markAllNotificationsSeen) {
      await client.notifications.markAllNotificationsSeen();
      console.log('Successfully marked all notifications as seen using dedicated method.');
    } else if (client.core && client.core.fetch) {
      await client.core.fetch('/notifications/seen', { method: 'POST' });
      console.log('Successfully marked all notifications as seen using core.fetch.');
    } else {
      // Use internal client call
      const request = new RequestBuilder()
        .setBaseUrl(client.config.baseUrl || client.config.environment || Environment.DEFAULT)
        .setConfig(client.config)
        .setMethod('POST')
        .setPath('/notifications/seen')
        .setRequestSchema(z.any())
        .addAccessTokenAuth(client.config.token, 'Bearer')
        .setRequestContentType(ContentType.Json)
        .addResponse({
          schema: z.undefined(),
          contentType: ContentType.NoContent,
          status: 204,
        })
        .build();

      await client.notifications.client.call(request);
      console.log('Successfully marked all notifications as seen using internal client call.');
    }
  } catch (error) {
    console.error('Error marking notifications as seen:', error);
    process.exit(1);
  }
}

main();

